public  static ETGSalesOrderFixationController construct()
{
    return new ETGSalesOrderFixationController();
}

public static void main(Args    _args)
{
    ETGSalesOrderFixationController     salesOrderFixationController;
    ETGSalesOrderFixationContract       salesOrderFixationContract;
    SalesTable                          salesTable;

    salesOrderFixationController    =   ETGSalesOrderFixationController::construct();
    salesTable                     =   _args.record() as SalesTable;

    salesOrderFixationController    =   new ETGSalesOrderFixationController(
                                        classStr (ETGSalesOrderFixationService),
                                        methodStr(ETGSalesOrderFixationService , generateReportByGER),
                                        SysOperationExecutionMode::Synchronous);
    salesOrderFixationContract      =   salesOrderFixationController.getDataContractObject();

    salesOrderFixationContract.parmSalesId(salesTable.SalesId); // Setting the Value of sales order id

    salesOrderFixationController.parmArgs(_args);
    salesOrderFixationController.parmShowDialog(false);
    salesOrderFixationController.startOperation();
}
